      .then(
        (d) => {
          d.json().then((b) => {
            setBooks(() => b)
          });
        }
      )

  }
    , [])

  return (

    <>
        {books.map(book =>
            <h4>{book.title}</h4>)}
    </>

  );
}

export default App;
